import { PrismaClient, Role, TargetType, Severity, ScanStatus } from '@prisma/client';

const prisma = new PrismaClient();

async function main() {
  console.log('🌱 Starting Database Seeding...');

  // 1. Create Hackers & Admins
  const admin = await prisma.user.upsert({
    where: { email: 'admin@vulnx.hunter' },
    update: {},
    create: {
      email: 'admin@vulnx.hunter',
      passwordHash: '$2b$10$rKvVPZQGhXVz3qN5YJ5zKOXKZ8qF5YJ5zKOXKZ8qF5YJ5zKOXKZ8qO', // Password: admin123
      name: 'Agent Zero',
      role: Role.ADMIN,
    },
  });

  const researcher = await prisma.user.upsert({
    where: { email: 'hacker@vulnx.hunter' },
    update: {},
    create: {
      email: 'hacker@vulnx.hunter',
      passwordHash: '$2b$10$rKvVPZQGhXVz3qN5YJ5zKOXKZ8qF5YJ5zKOXKZ8qF5YJ5zKOXKZ8qH', // Password: hacker123
      name: 'CyberPhantom',
      role: Role.RESEARCHER,
    },
  });

  console.log(`👤 Users seeded: Admin (${admin.name}), Researcher (${researcher.name})`);

  // 2. Create Teams
  const alphaTeam = await prisma.team.create({
    data: {
      name: 'RedTeam Alpha',
      members: {
        create: [
          { userId: admin.id, role: 'LEAD' },
          { userId: researcher.id, role: 'MEMBER' },
        ],
      },
    },
  });

  console.log(`👥 Team seeded: ${alphaTeam.name}`);

  // 3. Create Targets
  const target1 = await prisma.target.create({
    data: {
      name: 'MegaCorp Main Domain',
      type: TargetType.DOMAIN,
      scope: 'megacorp.internal',
      priority: 'HIGH',
      tags: ['external-network', 'web-app'],
      teamId: alphaTeam.id,
    },
  });

  const target2 = await prisma.target.create({
    data: {
      name: 'Internal API Endpoint',
      type: TargetType.API,
      scope: 'https://api.internal.megacorp/v2',
      priority: 'CRITICAL',
      tags: ['internal', 'private-endpoints'],
      teamId: alphaTeam.id,
    },
  });

  console.log(`🎯 Targets seeded: ${target1.name}, ${target2.name}`);

  // 4. Create Mock Vulnerabilities
  await prisma.vulnerability.createMany({
    data: [
      {
        targetId: target1.id,
        title: 'SQL Injection in User Login Endpoint',
        type: 'SQL Injection',
        severity: Severity.CRITICAL,
        cvssScore: 9.8,
        description: 'Input parameter bypass on username input allows raw SQL command execution on PostgreSQL backend database.',
        remediation: 'Use parameterization / prepared statements in database adapter query blocks.',
      },
      {
        targetId: target1.id,
        title: 'Cross-Site Scripting (XSS) on Search Results',
        type: 'Reflected XSS',
        severity: Severity.HIGH,
        cvssScore: 7.5,
        description: 'Reflected payload allows arbitrary script injection inside user search parameter rendering.',
        remediation: 'Implement HTML entity encoding and strong Content Security Policies (CSP).',
      },
      {
        targetId: target2.id,
        title: 'SSRF in Internal Webhooks Hook Handler',
        type: 'SSRF',
        severity: Severity.HIGH,
        cvssScore: 8.2,
        description: 'Unvalidated URL forwarding allows remote actors to pivot request loops into loopback IP endpoints.',
        remediation: 'Implement strict IP white-listing for target webhook callback domains.',
      },
    ],
  });

  console.log('☣️ Mock Vulnerabilities seeded.');

  // 5. Create a Mock Scan with Logs
  const scan = await prisma.scan.create({
    data: {
      targetId: target1.id,
      status: ScanStatus.COMPLETED,
      startedAt: new Date(Date.now() - 3600000), // 1 hour ago
      finishedAt: new Date(),
      logs: {
        create: [
          { message: '[*] Starting subfinder subdomain enumeration...' },
          { message: '[+] Found 12 target subdomains.' },
          { message: '[*] Port scanning open ports via naabu...' },
          { message: '[+] Ports 80, 443, 8080 identified active.' },
          { message: '[*] Running nuclei security signatures...' },
          { message: '[!] Critical Vulnerability Found: SQL Injection on /login!' },
          { message: '[+] Scan pipeline completed successfully.' },
        ],
      },
    },
  });

  console.log(`🔍 Scan seeded: Status (${scan.status})`);
  console.log('✅ Database successfully seeded!');
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

